"use client";

import { useEffect, useState } from "react";
import { createPortal } from "react-dom";
import { X } from "lucide-react";
import { cn } from "../lib/utils";

export interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title?: React.ReactNode;
  children?: React.ReactNode;
  footer?: React.ReactNode;
  closeOnOverlayClick?: boolean;
  closeOnEsc?: boolean;
  lockScroll?: boolean;
  hideTopCloseButton?: boolean;
  className?: string;
  contentClassName?: string;
}

function Modal({
  isOpen,
  onClose,
  title,
  children,
  footer,
  closeOnOverlayClick = true,
  closeOnEsc = true,
  lockScroll = true,
  hideTopCloseButton = false,
  className,
  contentClassName,
}: ModalProps) {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!isOpen || !closeOnEsc) return;

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") onClose();
    };

    window.addEventListener("keydown", handleKeyDown);

    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, closeOnEsc, onClose]);

  useEffect(() => {
    if (!isOpen || !lockScroll) return;

    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    return () => {
      document.body.style.overflow = previousOverflow;
    };
  }, [isOpen, lockScroll]);

  if (!mounted || !isOpen) {
    return null;
  }

  return createPortal(
    <div
      className={cn(
        "fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4",
        className,
      )}
      role="presentation"
      onClick={() => {
        if (closeOnOverlayClick) {
          onClose();
        }
      }}
    >
      <div
        role="dialog"
        aria-modal="true"
        aria-label={typeof title === "string" ? title : "Modal"}
        className={cn(
          "w-full max-w-lg rounded-xl bg-surface p-5 text-foreground shadow-xl",
          contentClassName,
        )}
        onClick={(event) => event.stopPropagation()}
      >
        <div
          className={cn(
            "flex relative items-center pr-7",
            !hideTopCloseButton && "min-h-6",
          )}
        >
          {title && (
            <h2 className="text-base font-semibold leading-6">{title}</h2>
          )}
          {!hideTopCloseButton && (
            <button
              type="button"
              onClick={onClose}
              className="absolute right-0"
            >
              <X strokeWidth={1.8} size={22} />
            </button>
          )}
        </div>
        <div className={cn(hideTopCloseButton && !title ? "" : "mt-4")}>
          {children}
        </div>
        {footer ? (
          <div className="mt-5 flex justify-end gap-2">{footer}</div>
        ) : null}
      </div>
    </div>,
    document.body,
  );
}

export { Modal };

